import React from 'react';
import './Stock.css'

function DisplayStockData({ stockData }) {
  if (!stockData) {
    return <p>ENTER STOCK</p>;
  }
  const arrow = stockData.change > 0 ? '\u25B2' : '\u25BC';
  const mp = stockData.change > 0 ? '\x2b' : '\u2212';
  const isStockUp = stockData.change > 0;
  const changeValue = Math.abs(stockData.change);


  return (
    <div className='info'>
  <div className='symbol'>{stockData.symbol}</div>
  <div className='price'>{stockData.price}</div>
  <div className='value-change'>{mp}{changeValue}</div>
  <div className='p-change'>{arrow}{stockData.pChange}</div>
</div>
  );
}

export default DisplayStockData;
